const payload = $input.first().json;

// Meta lead ad form data comes as field_data array
const fieldData = payload.field_data || [];
const getField = (name) => {
  const field = fieldData.find(f => f.name === name);
  return field ? field.values?.[0] || field.value : null;
};

// Determine company_id from ad account or form name
let companyId = 1; // Default Grand Park Capital
const formName = (payload.form_name || payload.form_id || '').toLowerCase();
if (formName.includes('brand new now') || formName.includes('bnn')) companyId = 2;
if (formName.includes('tikkun')) companyId = 4;

const fullName = getField('full_name') || '';
const nameParts = fullName.split(' ');

return [{
  json: {
    lead: {
      email: getField('email'),
      phone: getField('phone_number') || getField('phone'),
      first_name: getField('first_name') || nameParts[0] || '',
      last_name: getField('last_name') || nameParts.slice(1).join(' ') || '',
      company_id: companyId,
      ad_id: payload.ad_id,
      form_id: payload.form_id,
      ghl_contact_id: null
    }
  }
}];
